var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"KANADE_JAPAN_NULL_NULL","text":{"KOREA":"예정대로 건강한 아이가 태어난 것 같군요.","JPN":"予定どおり、健康な子どもが生まれたようですね。","ENG":"I see your baby is healthy. As expected.","TWN":"似乎如預料中的生出個健康的寶寶呢。"},"stage":{"bg":"NANAHARA_NORMAL","slots":{"L":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_SERIOUS2"}}}},{"id":"L5_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"예, 당주님께서 당주 자리에 걸맞은 아이를 낳을 것이라 예견하셨으니 당연한 결과이지요.","JPN":"はい、ご当主が当主として相応しい子を産むと予言なさいましたので当然の結果です。","ENG":"Yes, it is obviously the sufficient baby that you have foreseen.","TWN":"是，我早就預知堂主會生出能夠繼承堂主位置的孩子，這是理所當然的結果。"},"stage":{"bg":"NANAHARA_NORMAL","slots":{"L":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"KANADE_JAPAN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NANAHARA_NORMAL","slots":{"L":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"하야미 공? 갑자기 왜 그러시나요?","JPN":"速水様？　急にどうされましたか？","ENG":"Is something bothering you, Dame Kanade?","TWN":"速水？怎麼不說話？"},"stage":{"bg":"NANAHARA_NORMAL","slots":{"L":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"KANADE_JAPAN_NULL_NULL","text":{"KOREA":"느낌이 이상합니다.","JPN":"おかしいです。","ENG":"I have a strange feeling.","TWN":"我有不好的預感。"},"stage":{"bg":"NANAHARA_NORMAL","slots":{"L":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"KANADE_JAPAN_NULL_NULL","text":{"KOREA":"당주님!","JPN":"ご当主様！","ENG":"My lady!","TWN":"堂主！"},"stage":{"bg":"NANAHARA_NORMAL","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"KANADE_JAPAN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NANAHARA_NORMAL","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"KANADE_JAPAN_NULL_NULL","text":{"KOREA":"산파, 이건……?","JPN":"産婆、これは……？","ENG":"What is this...?","TWN":"產婆，這是……？"},"stage":{"bg":"NANAHARA_NORMAL","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"DOC_NPC_NANAHARA_NULL","text":{"KOREA":"그, 그게…… 쌍둥이입니다.","JPN":"そ、それが……双子でございます。","ENG":"Th-the baby... They're twins.","TWN":"是，是……雙胞胎。"},"stage":{"bg":"NANAHARA_NORMAL","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"DOC_NPC_NANAHARA_NULL","text":{"KOREA":"하지만 두 번째 아이는 나올 때부터 숨을 쉬지 않고 있습니다.","JPN":"ですが、2番目の子は出てきた時から息をしておりません。","ENG":"But the second child hasn't been breathing since she came out.","TWN":"可是第二個一生出來就沒有呼吸。"},"stage":{"bg":"NANAHARA_NORMAL","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"KANADE_JAPAN_NULL_NULL","text":{"KOREA":"살릴 방법은 없는 것인가?","JPN":"蘇生させる方法はないのか？","ENG":"Is there any way to save the child?","TWN":"沒辦法救嗎？"},"stage":{"bg":"NANAHARA_NORMAL","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"DOC_NPC_NANAHARA_NULL","text":{"KOREA":"당장 할 수 있는 시도는 모두 해봤지만…… 소용없었습니다.","JPN":"今できることはすべて試してみたのですが……だめでした。","ENG":"I tried the best I could... but I failed.","TWN":"能做的我都做了……無奈還是回天乏術。"},"stage":{"bg":"NANAHARA_NORMAL","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"당초 1년 전 당주께서 출산을 예견한 아이는 한 명뿐이었습니다.","JPN":"そもそも1年前にご当主が出産を予言した子は一人だけでした。","ENG":"Lady Nanahara had only seen one child in her future.","TWN":"一年前我就看見堂主只會生出一個孩子，"},"stage":{"bg":"NANAHARA_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"두 번째 아이의 죽음은 처음부터 정해진 운명인 것이지요.","JPN":"2番目の子の死は最初から定められた運命なのでしょう。","ENG":"Which means that the other child’s death was meant to be fate.","TWN":"第二個會死掉是一開始就注定的。"},"stage":{"bg":"NANAHARA_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"KANADE_JAPAN_NULL_NULL","text":{"KOREA":"장로! 당주님 앞에서 어찌 말씀을 그리 하십니까!","JPN":"長老！　ご当主様の御前でなぜそのような話をされるのですか！","ENG":"Elder! How dare you speak ill in front of Lady Nanahara?!","TWN":"長老！您怎麼可以對堂主說這種話！"},"stage":{"bg":"NANAHARA_NORMAL","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"MASTER_NPC_NANAHARA_GRAND","text":{"KOREA":"그만……!","JPN":"そこまで……！","ENG":"Enough…!","TWN":"好了……！"},"stage":{"bg":"NANAHARA_NORMAL","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MASTER_NPC_NANAHARA_GRAND","text":{"KOREA":"그만하렴, 카나데.","JPN":"やめなさい、かなで。","ENG":"That is enough, Kanade.","TWN":"速水奏，別說了。"},"stage":{"bg":"NANAHARA_NORMAL","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}}]`);export{e as default};